form:Form.form:Scripts:
		function LOAD()
{          

	if(Ctrl('main').GetMode() == 'NEW')
	{
		Ctrl('c_estado').SetXValue("A");		
		BuscarUltimoNumeroComprobante();
	}  

	if(Ctrl('main').GetMode() == 'EDIT' && Ctrl('c_estado').GetXValue() == "P")
	{
		CtrlEnabled('c_consumo_per',false);
		CtrlEnabled('f_consumo',false);
		CtrlEnabled('c_estado',false);
		CtrlEnabled('oi_consumo',false);
		CtrlEnabled('e_importe',false);   
		CtrlEnabled('d_observaciones',false);		
	}    

	if(Ctrl('main').GetMode() == 'LIST_EDIT' && Ctrl('LIST').GetSelectAttrValue("c_estado") == "P")
	{
		CtrlEnabled("DELETE",false);
	}   

	if(Ctrl('main').GetMode() == 'LIST' || Ctrl('main').GetMode() == 'LIST_EDIT')
	{
		Ctrl('con').SetXValue(Ctrl('consumos').GetXValue()); 

	}
}                                 

function BuscarUltimoNumeroComprobante()
{       

	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();
    var xmlSalida = nSQL.GetXML(Ctrl("main").getResource("qry_nro"), "");
	var c_memoria = parseInt(Ctrl('con').GetXValue()) + 1;
	var c_bd = parseInt(xmlSalida.GetAttr('nro'));
    var c_final;
    if(c_memoria > c_bd)
    	c_final = c_memoria;
    else
    	c_final = c_bd;
	Ctrl('c_consumo_per').SetXValue(c_final.toString()); 


}      

function ListClick()
{ 
	var img,t;

	if (Ctrl("LIST"))
	{           
		if (Ctrl("LIST").RowsCount()==0)
		{
			CtrlEnabled("EDIT"  ,false);
			CtrlEnabled("DELETE",false);
		} else
		{
			img=Ctrl("LIST").GetSelectAttrValue("img").toUpperCase().split("/");
			img=img[img.length-1].split(".")[0];

			switch(img)
			{
				case "LOCK":
					CtrlEnabled("EDIT"  ,false);
					CtrlEnabled("DELETE",false);
				break;
				case "LOCKDEL":
					CtrlEnabled("EDIT"  ,true );
					CtrlEnabled("DELETE",false);
				break;
				case "LOCKEDIT":
					CtrlEnabled("EDIT"  ,false);
					CtrlEnabled("DELETE",true );
				break;
				default:
					CtrlEnabled("EDIT"  ,true);
					CtrlEnabled("DELETE",true);
				break;
			}
		}
	}

	if ((Ctrl("LockREG")) && (Ctrl("HiLockREG"))) 
	{                  

		Ctrl("LockREG").SetXValue(Ctrl("HiLockREG").GetXValue());
		CtrlEnabled("EDIT"  ,Ctrl("LockREG").GetXValue()!="1");
		CtrlEnabled("DELETE",Ctrl("LockREG").GetXValue()!="1");  

		for (t=0; t<Ctrl("main_Center").m_Children.length; t++)
			if (Ctrl("main_Center").m_Children[t].m_ID.substr(0,12)=="main_columns")
				Ctrl("main_Center").m_Children[t].SetEnabled(Ctrl("LockREG").GetXValue()!="1");
	}     

	if(Ctrl('main').GetMode() == 'LIST_EDIT')
	{
		if(Ctrl('LIST').GetSelectAttrValue("c_estado") == "P")
		{
			CtrlEnabled("DELETE",false);
		}
	}          

}

function ListDobleClick()
{             
	if (Ctrl("MOSTRAR")) 
		Ctrl("MOSTRAR").DoEvent("OnClick");
}           

function CHANGE()
{
     BuscarOiTipoConsumo();
}     


function BuscarOiTipoConsumo()
{            
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();
    var xmlSalida = nSQL.GetXML(Ctrl("main").getResource("qry_oi_consumo"), "<FILTER oi_consumo='"+Ctrl('oi_consumo').GetXValue()+"'/>");
	Ctrl('oi_tipo_consumo').SetXValue(xmlSalida.GetAttr('oi_tipo_consumo'));
}
